C++<pre><code>#include &lt;bits/stdc++.h&gt;
using namespace std;
/* run this program using the console pauser or add your own getch, system("pause") or input loop */
#define ll long long
const int maxx=2e5+10;
const ll INF=1e18;
int n,m,x;
vector&lt; pair&lt;int,int&gt; &gt; g[maxx*2];
bool vis[maxx*2];
ll dis[maxx*2],ans;
void add_edge(int u,int v,int w){
    g[u].push_back({v,w});
}
priority_queue&lt; pair&lt;ll,int&gt;, vector&lt; pair&lt;ll,int&gt; &gt;,greater&lt; pair&lt;ll,int&gt; &gt; &gt; q;
void dijkstra(){
    while(!q.empty()){
        pair&lt;ll,int&gt; p=q.top();
        q.pop();
        int u=p.second;
        if(vis[u]) continue;
        vis[u]=true;
        for(int v=0;v&lt;g[u].size();v++){
            int to=g[u][v].first,w=g[u][v].second;
            if(dis[to]&gt;dis[u]+w){
                dis[to]=dis[u]+w;
                q.push({dis[to],to});
            }
        }
    }
}
int main(int argc, char** argv) {
    cin&gt;&gt;n&gt;&gt;m&gt;&gt;x;
    for(int i=1;i&lt;=m;i++){
        int u,v;
        cin&gt;&gt;u&gt;&gt;v;
        add_edge(u,v,1);//建立现实图 
        add_edge(v+n,u+n,1);//建立镜像图 
    }
    //创建现实与镜像的连接线 
    for(int i=1;i&lt;=n;i++){
        add_edge(i,i+n,x);
        add_edge(i+n,i,x);
    }
    for(int i=1;i&lt;=2*n;i++){
        dis[i]=INF;
    }
    dis[1]=0;
    q.push({dis[1],1});
    dijkstra();
    ans=min(dis[n],dis[2*n]);
    cout&lt;&lt;ans&lt;&lt;endl;
    return 0;
}
